          </div> */}
        </div>

        {/* Stats Section - Now with continuous floating animation */}
        {/* <div className="about-stats">
          <div className="stat-item">
            {/* Icon Removed */}
        {/* <h4>230+</h4>
            <p>Projects Completed</p>
          </div>
          <div className="stat-item"> */}
        {/* Icon Removed */}
        {/* <h4>170+</h4>
            <p>Happy Clients</p>
          </div>
          <div className="stat-item"> */}
        {/* <div className="stat-icon">🤝</div> */}
        {/* Icon Removed */}
        {/* <h4>1.7k</h4>
            <p>Learners Trained</p>
          </div>
          <div className="stat-item"> */}
        {/* <div className="stat-icon">⭐</div> */}
        {/* Icon Removed */}
        {/* <h4>20+</h4>
            <p>Industries Served</p>
          </div>
        </div> */}
      </div>
    </div>
  );
};

export default About;

import React, { useRef, useLayoutEffect } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import './BusinessBoost.css';
import { Globe, Megaphone, ArrowUpRight } from 'lucide-react';
import greenCircle from '../../assets/green circle.png';

gsap.registerPlugin(ScrollTrigger);

const boostCardsData = [
    {
        title: "SaaS",
        description: "Cloud-based software solutions that are scalable, secure, and accessible anytime, anywhere.",
        bg: "#D6C1E8", // Lilac
        text: "#1F2937"
    },
    {
        title: "ERP",
        description: "Unified management platform for enterprises, schools, and colleges, streamlining academics, finance, and operations.",
        bg: "#AC58E9", // Ultraviolet (keep this violet color)
        text: "#FFFFFF",
        descriptionStyle: { paddingLeft: "50px" } // Adjusted padding for longer text
    },
    {
        title: "CRM",
        description: "Smart customer relationship tools to manage leads, sales, and customer engagement seamlessly.",
        bg: "#08262C", // Dark Teal (Kept existing)
        text: "#FFFFFF"
    },
    {
        title: "Business Suite AI",
        description: "AI-powered business tools that automate operations, improve decisions, and boost productivity.",
        bg: "#124A59", // Medium Teal (Kept existing)
        text: "#FFFFFF"
    },
    {
        title: "AI Chatbot",
        description: "Intelligent conversational assistants that provide instant support and enhance user experience.",
        bg: "#F4F8F9", // Frosted Snow (Kept existing)
        text: "#1F2937"
    },
    {
        title: "Job Seeker",
        description: "A smart platform connecting talent with opportunities through AI-driven job matching.",
        bg: "#292F91", // Previous SaaS Blue (Dark Blue)
        text: "#FFFFFF"
    },
    {
        title: "Learning & Career",
        description: "Interactive learning systems designed to upskill individuals and accelerate career growth.",
        bg: "#4CA8DD", // Previous ERP Blue (Light Blue)
        text: "#FFFFFF"
    }
];

const BusinessBoost = () => {
    const sectionRef = useRef(null);
    const scrollTrackRef = useRef(null);

    useLayoutEffect(() => {
        const ctx = gsap.context(() => {
            // Infinite vertical scrolling animation using GSAP
            if (scrollTrackRef.current) {
                const totalHeight = scrollTrackRef.current.scrollHeight / 2; // Half because content is duplicated
                const cards = gsap.utils.toArray('.boost-card');

                // Vertical scrolling animation
                gsap.set(scrollTrackRef.current, { y: 0 });

                const scrollTween = gsap.to(scrollTrackRef.current, {
                    y: -totalHeight,
                    duration: 30,
                    ease: "none",
                    repeat: -1,
                    modifiers: {
                        y: gsap.utils.unitize(y => parseFloat(y) % totalHeight)
                    }
                });
            }
        }, sectionRef);

        return () => ctx.revert();
    }, []);

    return (
        <section className="business-boost-section" ref={sectionRef}>
            <div className="business-boost-container">
                {/* Left Section */}
                <div className="boost-left-section">
                    <h2 className="boost-intro-text">
                        Build an AI product
                        <span className="highlight-faster">
                            faster
                            <img src={greenCircle} alt="" className="faster-bg" />
                        </span>
                        than ever.
                    </h2>
                    <h1 className="boost-main-title">
                        <span className="boost-highlight">10x...</span>
                        <br />
                        <span className="boost-title-main">Boost</span>
                        <br />
                        <span className="boost-subtitle">Your Business</span>
                    </h1>

                    <p className="boost-description">
                        Whether you want to take your business global or just expand your horizons, we will help you identify new customers.
                    </p>

                    <button className="boost-cta-button">
                        Get started
                        <span className="cta-icon"><ArrowUpRight size={30} strokeWidth={3.5} /></span>
                    </button>

                    <div className="boost-stats">
                        <div className="stat-item">
                            <div className="stat-icon-wrapper">
                                <Globe className="stat-icon-svg" strokeWidth={2.5} />
                            </div>
                            <div className="stat-text">
                                <h4>Your Global Expansion</h4>
                                <p>Digital Partner</p>
                            </div>
                        </div>
                        <div className="stat-item">
                            <div className="stat-icon-wrapper">
                                <Megaphone className="stat-icon-svg" strokeWidth={2.5} />
                            </div>
                            <div className="stat-textt">
                                <h4>Driving Customer Acquisition</h4>
                                <p>Celebrating Five Years Strong</p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right Section - Infinite Scrolling Cards */}
                <div className="boost-right-section">
                    <div className="scroll-track" ref={scrollTrackRef}>
                        {/* Original Cards */}
                        {boostCardsData.map((card, index) => (
                            <div
                                className="boost-card"
                                key={`original-${index}`}
                                style={{ backgroundColor: card.bg, color: card.text }}
                            >
                                <div className="card-content-wrapper">
                                    <h3 className="card-title-left">{card.title}</h3>
                                    <p className="card-description-right">{card.description}</p>
                                </div>
                                <span className="card-arrow">→</span>
                            </div>
                        ))}

                        {/* Duplicated Cards for Infinite Scroll */}
                        {boostCardsData.map((card, index) => (
                            <div
                                className="boost-card"
                                key={`duplicate-${index}`}
                                style={{ backgroundColor: card.bg, color: card.text }}
                            >
                                <div className="card-content-wrapper">
                                    <h3 className="card-title-left">{card.title}</h3>
                                    <p className="card-description-right">{card.description}</p>
                                </div>
                                <span className="card-arrow">→</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </section>
    );
};

export default BusinessBoost;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faArrowUp, faTicketSimple } from '@fortawesome/free-solid-svg-icons';
import aiProductWork from '../../assets/AiImage.jpeg';
import './CoreServices.css';

// Import icons
// import brandingIcon from '../../assets/branding.png';
const brandingIcon = "";
// import developmentIcon from '../../assets/development';
const developmentIcon = "";
// import marketingIcon from '../../assets/Testing.png';
const marketingIcon = "";
// import aiIcon from '../../assets/ai.png';
const aiIcon = "";
// import educationIcon from '../../assets/ai.png';
const educationIcon = "";

// Import work showcase images
// import uiuxWork from '../../assets/uiux_work.png';
const uiuxWork = "";
// import webDevWork from '../../assets/web_dev_work.png';
const webDevWork = "";
// import marketingWork from '../../assets/marketing_work.png';
const marketingWork = "";
// import brandingWork from '../../assets/branding_work.png';
const brandingWork = "";
// import appsDevWork from '../../assets/apps_dev_work.png';
const appsDevWork = "";


// Import background images
const backgroundImages = {
  branding: 'https://images.unsplash.com/photo-1561070791-2526d30994b5?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80',
  development: 'https://images.unsplash.com/photo-1555066931-4365d14bab8c?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80',
  marketing: 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80',
  ai: 'https://images.unsplash.com/photo-1677442136019-21780ecad995?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80',
  education: 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80'
};

const CoreServices = () => {
  const navigate = useNavigate();
  const [currentIndex, setCurrentIndex] = useState(1);
  const [isAutoPlaying, setIsAutoPlaying] = useState(true);

  const minIndex = 1;
  const maxIndex = 3; // services.length - 3 (6 - 3 = 3) for 4 visible cards

  const services = [
    {
      id: 1,
      title: "Designing",
      description: "Crafting memorable brand identities that resonate with your audience and drive business growth through strategic design thinking.",
      icon: brandingIcon,
      background: backgroundImages.branding,
      features: ["Logo & Identity", "Brand Strategy", "UI/UX Design", "Visual Systems"],
      color: "#18181A",
      route: '/marketingPage'
    },
    {
      id: 2,
      title: "Development",
      description: "Building cutting-edge digital experiences with robust, scalable solutions that perform across all platforms and devices.",
      icon: developmentIcon,
      background: backgroundImages.development,
      features: ["Web Development", "Mobile Apps", "E-commerce", "Progressive Web Apps"],
      color: "#6D28D9",
      route: '/developmentPage'
    },
    {
      id: 3,
      title: "SAAS",
      description: "Building scalable, multi-tenant software solutions that empower businesses to deliver high-quality digital services at scale.",
      icon: marketingIcon,
      background: backgroundImages.marketing,
      features: ["Multi-tenancy", "Scalable Cloud", "API Management", "Enterprise Security"],
      color: "#18181A",
      route: '/saasPage'
    },
    {
      id: 4,
      title: "Branding",
      description: "Empowering teams and individuals with cutting-edge skills and knowledge through comprehensive training programs.",
      icon: educationIcon,
      background: backgroundImages.education,
      features: ["Corporate Training", "Branding", "UI Designs", "Label design"],
      color: "#6D28D9",
      route: '/brandingPage'
    },
    {
      id: 5,
      title: "Data Analytics",
      description: "Transforming Ideas into Powerful Mobile Experiences.",
      icon: aiIcon,
      background: backgroundImages.ai,
      features: ["Api Integration", "cross paltform support", "personalization", "Data Encryption"],
      color: "#18181A",
      route: '/mobileApplicationsPage'
    },
    {
      id: 6,
      title: "AI Product",
      description: "Developing intelligent solutions that automate processes, improve decision-making, and drive innovation.",
      icon: aiIcon,
      background: aiProductWork,
      features: ["Machine Learning", "NLP", "Predictive Analytics", "Process Automation"],
      color: "#6D28D9",
      route: '/aiPage'
    }
  ];

  useEffect(() => {
    let interval;

    if (isAutoPlaying) {
      interval = setInterval(() => {
        setCurrentIndex((prevIndex) =>
          prevIndex >= maxIndex ? minIndex : prevIndex + 1
        );
      }, 2000);
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isAutoPlaying, maxIndex]);

  const nextSlide = () => {
    setCurrentIndex(currentIndex >= maxIndex ? minIndex : currentIndex + 1);
  };

  const prevSlide = () => {
    setCurrentIndex(currentIndex <= minIndex ? maxIndex : currentIndex - 1);
  };

  const goToSlide = (index) => {
    let target = Math.max(minIndex, Math.min(index, maxIndex));
    setCurrentIndex(target);
  };

  const handleServiceClick = (route) => {
    navigate(route);
  };

  return (
    <section
      id="CoreServices"
      className="services-carousel-section"
      onMouseEnter={() => setIsAutoPlaying(false)}
      onMouseLeave={() => setIsAutoPlaying(true)}
    >
      <div className="carousel-main-container">
        {/* Header */}
        <div className="carousel-header">
          <div className="header-top-row">
            <h2 className="carousel-title">Our Works</h2>
            <p className="carousel-subtitle">
              Explore our recent portfolio showcasing the successful works for our client.
            </p>
          </div>
        </div>

        {/* Carousel */}
        <div className="carousel-full-wrapper">
          <div className="carousel-controls-top">
            <button className="carousel-btn" onClick={prevSlide}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="15 18 9 12 15 6"></polyline>
              </svg>
            </button>
            <button className="carousel-btn" onClick={nextSlide}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="9 18 15 12 9 6"></polyline>
              </svg>
            </button>
          </div>

          <div className="carousel-full-container">
            <div
              className="carousel-track"
              style={{
                '--current-index': currentIndex,
                '--slide-count': services.length
              }}
            >
              {services.map((service, index) => {
                const isCenter = index === currentIndex;
                return (
                  <div
                    key={service.id}
                    className={`carousel-slide ${isCenter ? 'center-card' : 'side-card'}`}
                    onClick={() => handleServiceClick(service.route)}
                  >
                    <div
                      className="slide-bg-image"
                      style={{ backgroundImage: `url(${service.background})` }}
                    ></div>

                    <div className="slide-wrapper">
                      <div
                        className="slide-content"
                        style={{
                          '--card-bg': service.color,
                        }}
                      >
                        <div className="card-ui-header">
                          <h3 className="card-ui-title">{service.title}</h3>
                        </div>

                        <div className="card-mockup-area">
                          <div
                            className="mockup-bg"
                            style={{ backgroundImage: `url(${service.background})` }}
                          ></div>
                        </div>
                      </div>

                      <div className="card-ui-action">
                        <div className="action-circle" style={{
                          backgroundColor: (service.id === 2 || service.id === 4 || service.id === 6) ? '#C0FF2D' : '#333',
                        }}>
                          <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                            <path
                              d="M7 17L17 7M17 7H7M17 7V17"
                              stroke={(service.id === 2 || service.id === 4 || service.id === 6) ? 'black' : 'white'}
                              strokeWidth="2"
                              strokeLinecap="round"
                              strokeLinejoin="round"
                            />
                          </svg>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Indicators */}
          <div className="color-dots-indicators">
            {services.map((service, index) => (
              <button
                key={index}
                className={`color-dot ${index === currentIndex ? 'active' : ''}`}
                onClick={() => goToSlide(index)}
                style={{
                  backgroundColor: service.color
                }}
              />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default CoreServices;

import React, { useLayoutEffect, useState, useRef } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import './DoubleMarquees.css';
import buyerImage from '../../assets/bg1.jpeg';
import characterIllustration from '../../assets/character-illustration.png';
import expertiseBg from '../../assets/OurExperise&Learning.png';

gsap.registerPlugin(ScrollTrigger);

const DoubleMarquees = () => {
  const containerRef = useRef(null);
  const titleRef = useRef(null);
  const shapesRef = useRef(null);
  const contentWrapperRef = useRef(null);
  const techTrackRef = useRef(null);
  const learningTrackRef = useRef(null);

  useLayoutEffect(() => {
    const ctx = gsap.context(() => {
      // 1️⃣ CONTENT REVEAL (Blur -> Sharp)
      gsap.fromTo(containerRef.current,
        {
          opacity: 0,
          scale: 0.95,
          filter: "blur(12px)", // Initial content blur
          rotationX: 0,
          rotationY: 0
        },
        {
          opacity: 1,
          scale: 1,
          filter: "blur(0px)", // Clear content blur
          duration: 1.5,
          ease: "power3.out",
          scrollTrigger: {
            trigger: containerRef.current,
            start: "top 85%",
            end: "top 20%",
            scrub: 1
          }
        }
      );

      // 1b️⃣ GLASS BLUR INTENSITY (Background Blur)
      gsap.fromTo('.glass-overlay',
        { backdropFilter: "blur(5px)" },
        {
          backdropFilter: "blur(20px)",
          ease: "none",
          scrollTrigger: {
            trigger: containerRef.current,
            start: "top bottom",
            end: "bottom top",
            scrub: true
          }
        }
      );

      // 2️⃣ REFLECTION SWEEP
      gsap.to('.reflection-overlay', {
        x: '200%',
        duration: 6,
        repeat: -1,
        ease: "none",
        delay: 1
      });

      // 3️⃣ ITEM SHIMMER (Subtle continuous flow)
      gsap.to('.item-shimmer', {
        x: '200%',
        duration: 3,
        repeat: -1,
        ease: "sine.inOut",
        stagger: {
          each: 0.2,
          from: "random"
        }
      });

      // 4️⃣ GLOW PULSE (Maintained)
      gsap.to('.item-glow', {
        opacity: 0.6,
        scale: 1.3,
        duration: 3,
        repeat: -1,
        yoyo: true,
        ease: "sine.inOut",
        stagger: {
          each: 0.1,
          from: "random"
        }
      });

      // 5️⃣ 3D TILT DASHBOARD EFFECT (Desktop Only)
      if (window.innerWidth > 768) {
        containerRef.current.addEventListener('mousemove', (e) => {
          const rect = containerRef.current.getBoundingClientRect();
          const x = e.clientX - rect.left;
          const y = e.clientY - rect.top;
          const centerX = rect.width / 2;
          const centerY = rect.height / 2;

          // Calculate slight rotation (max 3-5 degrees)
          const rotateX = ((y - centerY) / centerY) * -3;
          const rotateY = ((x - centerX) / centerX) * 3;

          gsap.to(containerRef.current, {
            rotationX: rotateX,
            rotationY: rotateY,
            scale: 1.01,
            duration: 0.5,
            ease: "power3.out",
            overwrite: "auto"
          });

          // Parallax for inner elements
          gsap.to(shapesRef.current, { x: rotateY * 15, y: -rotateX * 15, duration: 0.5 });
          gsap.to(titleRef.current, { x: rotateY * 5, y: -rotateX * 5, duration: 0.5 });
        });

        // Reset on leave
        containerRef.current.addEventListener('mouseleave', () => {
          gsap.to(containerRef.current, {
            rotationX: 0,
            rotationY: 0,
            scale: 1,
            duration: 0.8,
            ease: "power3.out",
            overwrite: "auto"
          });
          gsap.to([shapesRef.current, titleRef.current], { x: 0, y: 0, duration: 0.8 });
        });
      }

      // 6️⃣ MARQUEE LOOP + DYNAMIC SPEED
      const createMarquee = (target, direction = -1) => {
        const totalWidth = target.scrollWidth / 10;
        gsap.set(target, { x: direction === 1 ? -totalWidth : 0 });

        const tl = gsap.to(target, {
          x: direction === 1 ? 0 : -totalWidth,
          duration: 500, // Significantly slower base speed
          ease: "none",
          repeat: -1
        });
        return tl;
      };

      const techScroll = createMarquee(techTrackRef.current, -1);
      const learningScroll = createMarquee(learningTrackRef.current, 1);

      ScrollTrigger.create({
        trigger: containerRef.current,
        onUpdate: (self) => {
          const velocity = Math.abs(self.getVelocity());
          const timeScale = 1 + (velocity / 250); // Reduced sensitivity

          gsap.to([techScroll, learningScroll], {
            timeScale: timeScale > 2 ? 2 : timeScale, // Capped max speed
            duration: 0.2,
            overwrite: true
          });

          gsap.to([techScroll, learningScroll], {
            timeScale: 1,
            duration: 1.5,
            delay: 0.2
          });
        }
      });

    }, containerRef);
    return () => ctx.revert();
  }, []);

  const techServices = [
